import{_ as i,o as a,c as e,a9 as h}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"主从复制与高可用","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/07-MySQL学习/06-主从复制与高可用.md","filePath":"语言/java/07-MySQL学习/06-主从复制与高可用.md","lastUpdated":1777106511000}'),s={name:"语言/java/07-MySQL学习/06-主从复制与高可用.md"};function r(n,l,t,p,d,o){return a(),e("div",null,[...l[0]||(l[0]=[h(`<h1 id="主从复制与高可用" tabindex="-1">主从复制与高可用 <a class="header-anchor" href="#主从复制与高可用" aria-label="Permalink to “主从复制与高可用”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>主从复制用于把主库的数据变更同步到从库。<br> 高可用则关注数据库节点故障时系统如何保持服务能力。</p><p>一句话理解：</p><ul><li>主从复制解决的是“数据怎么从主库同步出去”</li><li>高可用解决的是“主库或节点出问题时怎么办”</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>数据库往往是系统最关键的状态中心。<br> 如果不理解复制和高可用，系统在这些场景下会很被动：</p><ul><li>扩展读能力</li><li>数据容灾</li><li>节点故障恢复</li><li>故障切换</li></ul><h2 id="_3-先建立直觉-有从库不等于天然高可用" tabindex="-1">3. 先建立直觉：有从库不等于天然高可用 <a class="header-anchor" href="#_3-先建立直觉-有从库不等于天然高可用" aria-label="Permalink to “3. 先建立直觉：有从库不等于天然高可用”">​</a></h2><p>这是学习这章最重要的一条直觉。</p><p>很多人会以为：</p><ul><li>有主从复制</li><li>就已经高可用了</li></ul><p>其实不是。<br> 复制只说明：</p><ul><li>数据在同步</li></ul><p>但高可用还要额外解决：</p><ul><li>节点故障检测</li><li>角色切换</li><li>业务接入切换</li><li>延迟一致性问题</li></ul><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-binlog" tabindex="-1">4.1 Binlog <a class="header-anchor" href="#_4-1-binlog" aria-label="Permalink to “4.1 Binlog”">​</a></h3><p>MySQL 主从复制最核心的基础之一是：</p><ul><li>Binlog</li></ul><p>你可以先把它理解成：</p><ul><li>主库上的变更日志</li></ul><p>从库正是基于这些变更日志去追赶主库状态。</p><h3 id="_4-2-主从复制基本流程" tabindex="-1">4.2 主从复制基本流程 <a class="header-anchor" href="#_4-2-主从复制基本流程" aria-label="Permalink to “4.2 主从复制基本流程”">​</a></h3><p>学习阶段先记这条主线就够用：</p><ol><li>主库写入数据并记录 binlog</li><li>从库拉取主库日志</li><li>从库重放日志</li><li>从库数据逐步追平主库</li></ol><p>所以复制不是“瞬时魔法同步”，而是一个：</p><ul><li>拉取 + 重放 + 追平</li></ul><p>的过程。</p><h3 id="_4-3-读写分离" tabindex="-1">4.3 读写分离 <a class="header-anchor" href="#_4-3-读写分离" aria-label="Permalink to “4.3 读写分离”">​</a></h3><p>主从复制很常见的落地方向是：</p><ul><li>主库负责写</li><li>从库负责读</li></ul><p>它的价值在于：</p><ul><li>分担读压力</li></ul><p>但它也带来新的问题：</p><ul><li>主从延迟</li><li>读到旧数据</li></ul><h3 id="_4-4-复制延迟" tabindex="-1">4.4 复制延迟 <a class="header-anchor" href="#_4-4-复制延迟" aria-label="Permalink to “4.4 复制延迟”">​</a></h3><p>复制延迟是主从架构里非常关键的问题。<br> 典型现象是：</p><ul><li>数据已经写入主库</li><li>但从库还没追上</li><li>结果读请求读到了旧值</li></ul><p>这对这些场景尤其敏感：</p><ul><li>写后立刻读</li><li>强一致查询</li><li>状态流转类业务</li></ul><h3 id="_4-5-故障切换" tabindex="-1">4.5 故障切换 <a class="header-anchor" href="#_4-5-故障切换" aria-label="Permalink to “4.5 故障切换”">​</a></h3><p>高可用体系里最关键的问题之一就是：</p><ul><li>主库挂了以后，谁接替它</li></ul><p>这通常涉及：</p><ul><li>主从角色切换</li><li>服务发现或连接配置切换</li><li>业务恢复过程</li></ul><h3 id="_4-6-高可用方案基本思路" tabindex="-1">4.6 高可用方案基本思路 <a class="header-anchor" href="#_4-6-高可用方案基本思路" aria-label="Permalink to “4.6 高可用方案基本思路”">​</a></h3><p>学习阶段先抓住概念主线即可：</p><ul><li>复制提供数据同步能力</li><li>监控和选主机制提供切换依据</li><li>接入层切换保证业务流量继续可达</li></ul><h2 id="_5-学习重点" tabindex="-1">5. 学习重点 <a class="header-anchor" href="#_5-学习重点" aria-label="Permalink to “5. 学习重点”">​</a></h2><p>这一章最重要的是掌握：</p><ul><li>主从复制依赖 binlog 等日志机制</li><li>复制的主要目标是扩展读能力和容灾</li><li>读写分离会带来一致性风险</li><li>高可用一定伴随切换成本和管理复杂度</li><li>有复制不等于真正高可用</li></ul><h2 id="_6-常见问题" tabindex="-1">6. 常见问题 <a class="header-anchor" href="#_6-常见问题" aria-label="Permalink to “6. 常见问题”">​</a></h2><h3 id="_6-1-读写分离后忽略主从延迟" tabindex="-1">6.1 读写分离后忽略主从延迟 <a class="header-anchor" href="#_6-1-读写分离后忽略主从延迟" aria-label="Permalink to “6.1 读写分离后忽略主从延迟”">​</a></h3><p>这会让业务在“写后马上读”场景下出现诡异问题。</p><h3 id="_6-2-只关注吞吐-不关注故障恢复" tabindex="-1">6.2 只关注吞吐，不关注故障恢复 <a class="header-anchor" href="#_6-2-只关注吞吐-不关注故障恢复" aria-label="Permalink to “6.2 只关注吞吐，不关注故障恢复”">​</a></h3><p>这会让系统平时看起来很强，一出故障就很脆。</p><h3 id="_6-3-认为有从库就天然高可用" tabindex="-1">6.3 认为有从库就天然高可用 <a class="header-anchor" href="#_6-3-认为有从库就天然高可用" aria-label="Permalink to “6.3 认为有从库就天然高可用”">​</a></h3><p>复制和高可用不是同一件事。</p><h2 id="_7-动手验证" tabindex="-1">7. 动手验证 <a class="header-anchor" href="#_7-动手验证" aria-label="Permalink to “7. 动手验证”">​</a></h2><p>当前环境没有 <code>mysql</code> 客户端，也没有可直接操作的主从集群，所以这一节改成“架构验证步骤 + 观察点”。</p><h3 id="_7-1-复制链路验证思路" tabindex="-1">7.1 复制链路验证思路 <a class="header-anchor" href="#_7-1-复制链路验证思路" aria-label="Permalink to “7.1 复制链路验证思路”">​</a></h3><p>如果你在真实 MySQL 环境中做实验，建议重点观察：</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">MASTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> STATUS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">REPLICA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> STATUS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G</span></span></code></pre></div><p>或旧版本兼容命令：</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHOW SLAVE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">STATUS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\G</span></span></code></pre></div><p>重点看：</p><ul><li>当前主库 binlog 位点</li><li>从库复制线程状态</li><li>延迟时间</li></ul><h3 id="_7-2-读写分离一致性演练" tabindex="-1">7.2 读写分离一致性演练 <a class="header-anchor" href="#_7-2-读写分离一致性演练" aria-label="Permalink to “7.2 读写分离一致性演练”">​</a></h3><p>你可以设计一个最小场景：</p><ol><li>向主库插入一条新记录</li><li>立刻从从库查询</li><li>观察是否立即可见</li></ol><p>这个实验很适合理解：</p><ul><li>主从延迟为什么会变成业务问题</li></ul><h3 id="_7-3-高可用思考题" tabindex="-1">7.3 高可用思考题 <a class="header-anchor" href="#_7-3-高可用思考题" aria-label="Permalink to “7.3 高可用思考题”">​</a></h3><p>可以把自己代入生产环境问三个问题：</p><ol><li>主库挂了以后，谁来发现？</li><li>发现后，谁来切换角色？</li><li>切换后，应用连接怎么更新？</li></ol><p>这三个问题答不完整，就说明“复制”和“高可用”还没有真正连起来。</p><h2 id="_8-练习建议" tabindex="-1">8. 练习建议 <a class="header-anchor" href="#_8-练习建议" aria-label="Permalink to “8. 练习建议”">​</a></h2><ul><li>画出主从复制流程图</li><li>思考一个读写分离场景下的一致性风险</li><li>总结常见数据库高可用方案差异</li><li>用自己的话解释“为什么有从库不等于高可用”</li></ul><h2 id="_9-自测问题" tabindex="-1">9. 自测问题 <a class="header-anchor" href="#_9-自测问题" aria-label="Permalink to “9. 自测问题”">​</a></h2><ul><li>MySQL 主从复制依赖什么日志机制？</li><li>主从延迟会带来什么业务问题？</li><li>为什么“有复制”不等于“高可用”？</li><li>读写分离为什么会引入一致性风险？</li></ul><h2 id="_10-自测核对要点" tabindex="-1">10. 自测核对要点 <a class="header-anchor" href="#_10-自测核对要点" aria-label="Permalink to “10. 自测核对要点”">​</a></h2><ul><li>Binlog 是主从复制的重要基础</li><li>主从复制主要解决扩展读能力和容灾问题</li><li>主从延迟会直接影响业务一致性体验</li><li>高可用必须包含故障检测、切换和接入恢复能力</li></ul>`,83)])])}const _=i(s,[["render",r]]);export{k as __pageData,_ as default};
